        // Create an instance of CSVFormat
        CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n", "\\N",
                new Object[]{"Header comment"}, new String[]{"Header1", "Header2"}, false, true, false, true, false);

        // Use reflection to access and set the private field
        java.lang.reflect.Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormat, '#');

        // Verify the getCommentMarker method
        assertEquals('#', csvFormat.getCommentMarker());
    }

